<template>
  <view class="page">
    <view class="header">
      <text class="title">管理后台</text>
      <text class="sub">Token 已校验 · 共 {{ productCount }} 个商品（含下架）</text>
    </view>

    <view class="card">
      <view class="cell" @click="goProductManage">
        <text class="cell-icon">📦</text>
        <view class="cell-body">
          <text class="cell-title">商品管理</text>
          <text class="cell-desc">上下架、规格、描述与图片</text>
        </view>
        <text class="cell-arrow">›</text>
      </view>
    </view>

    <button class="logout-admin" @click="onLogoutAdmin">退出管理登录</button>
    <view class="tip">业务接口请使用 common/api/adminApi.js 中的 adminRequest。</view>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onShow } from '@dcloudio/uni-app';
import {
  getAdminToken,
  clearAdminToken,
  adminGetProducts,
} from '@/common/api/adminApi.js';

const productCount = ref('—');

const loadStats = async () => {
  try {
    const list = await adminGetProducts();
    productCount.value = Array.isArray(list) ? String(list.length) : '—';
  } catch {
    productCount.value = '—';
  }
};

onShow(() => {
  if (!getAdminToken()) {
    uni.redirectTo({ url: '/pages/admin/login' });
    return;
  }
  loadStats();
});

const goProductManage = () => {
  uni.showToast({ title: '商品管理页开发中', icon: 'none' });
};

const onLogoutAdmin = () => {
  clearAdminToken();
  uni.showToast({ title: '已退出', icon: 'none' });
  setTimeout(() => {
    uni.redirectTo({ url: '/pages/admin/login' });
  }, 300);
};
</script>

<style lang="scss" scoped>
.page {
  min-height: 100vh;
  background: #f5f6f8;
  padding: 40rpx 32rpx 80rpx;
  box-sizing: border-box;
}
.header {
  margin-bottom: 40rpx;
  .title {
    font-size: 40rpx;
    font-weight: 700;
    color: #1a1a1a;
    display: block;
  }
  .sub {
    font-size: 24rpx;
    color: #666;
    margin-top: 12rpx;
    display: block;
  }
}
.card {
  background: #fff;
  border-radius: 20rpx;
  overflow: hidden;
  box-shadow: 0 4rpx 20rpx rgba(0, 0, 0, 0.06);
}
.cell {
  display: flex;
  align-items: center;
  padding: 36rpx 28rpx;
  .cell-icon {
    font-size: 44rpx;
    margin-right: 24rpx;
  }
  .cell-body {
    flex: 1;
    .cell-title {
      font-size: 32rpx;
      color: #333;
      display: block;
    }
    .cell-desc {
      font-size: 24rpx;
      color: #999;
      margin-top: 8rpx;
      display: block;
    }
  }
  .cell-arrow {
    font-size: 36rpx;
    color: #ccc;
  }
}
.logout-admin {
  margin-top: 48rpx;
  background: #fff;
  color: #023993;
  border: 2rpx solid #023993;
  border-radius: 48rpx;
  font-size: 28rpx;
  &::after {
    border: none;
  }
}
.tip {
  margin-top: 40rpx;
  font-size: 22rpx;
  color: #bbb;
  line-height: 1.6;
  padding: 0 8rpx;
}
</style>
